// src/pages/Settings.jsx
import { useState, useEffect } from "react";
import api from "../utils/api";

const FIELDS = [
  { key: "shop_name",          label: "Shop / Pharmacy Name",   type: "text" },
  { key: "shop_address",       label: "Address",                type: "text" },
  { key: "shop_phone",         label: "Phone Number",           type: "text" },
  { key: "shop_gstin",         label: "GSTIN",                  type: "text" },
  { key: "invoice_prefix",     label: "Invoice Prefix",         type: "text" },
  { key: "invoice_counter",    label: "Invoice Counter (last)", type: "number" },
  { key: "low_stock_threshold",label: "Low Stock Alert (qty)",  type: "number" },
  { key: "expiry_alert_days",  label: "Expiry Alert (days)",    type: "number" },
];

export default function Settings() {
  const [form,    setForm]    = useState({});
  const [loading, setLoading] = useState(true);
  const [saving,  setSaving]  = useState(false);
  const [saved,   setSaved]   = useState(false);

  useEffect(() => {
    api.get("/settings").then(r => {
      setForm(r.data || {});
      setLoading(false);
    });
  }, []);

  const save = async () => {
    setSaving(true); setSaved(false);
    try {
      await api.put("/settings", form);
      setSaved(true);
      setTimeout(() => setSaved(false), 2500);
    } finally { setSaving(false); }
  };

  if (loading) return <div className="empty-state"><span className="spinner" /></div>;

  return (
    <div className="page-content" style={{ maxWidth: 580 }}>
      <div className="card">
        <div className="card-title">Shop Information</div>
        {FIELDS.map(f => (
          <div className="form-group" key={f.key}>
            <label>{f.label}</label>
            <input
              className="input"
              type={f.type}
              value={form[f.key] || ""}
              onChange={e => setForm({ ...form, [f.key]: e.target.value })}
            />
          </div>
        ))}

        {saved && <div className="alert alert-success">✅ Settings saved successfully</div>}

        <div style={{ marginTop: 16 }}>
          <button className="btn btn-primary btn-lg" onClick={save} disabled={saving}>
            {saving ? <span className="spinner" /> : "Save Settings"}
          </button>
        </div>
      </div>

      <div className="card mt-16">
        <div className="card-title">About</div>
        <div style={{ fontSize: 13, color: "var(--text2)", lineHeight: 1.8 }}>
          <div><span style={{ color: "var(--text3)" }}>App:</span> MediCare Pharmacy POS</div>
          <div><span style={{ color: "var(--text3)" }}>Version:</span> 1.0.0</div>
          <div><span style={{ color: "var(--text3)" }}>Storage:</span> SQLite (offline)</div>
          <div><span style={{ color: "var(--text3)" }}>Backend:</span> Node.js + Express</div>
        </div>
      </div>
    </div>
  );
}
