// src/pages/Reports.jsx
import { useState, useEffect } from "react";
import api from "../utils/api";

export default function Reports() {
  const [tab,       setTab]       = useState("daily");
  const [date,      setDate]      = useState(new Date().toISOString().split("T")[0]);
  const [fromDate,  setFromDate]  = useState(() => {
    const d = new Date(); d.setDate(d.getDate()-30); return d.toISOString().split("T")[0];
  });
  const [toDate,    setToDate]    = useState(new Date().toISOString().split("T")[0]);
  const [data,      setData]      = useState(null);
  const [loading,   setLoading]   = useState(false);

  const load = async () => {
    setLoading(true); setData(null);
    try {
      let res;
      if (tab === "daily")     res = await api.get(`/reports/daily?date=${date}`);
      if (tab === "range")     res = await api.get(`/reports/range?from=${fromDate}&to=${toDate}`);
      if (tab === "lowstock")  res = await api.get(`/reports/low-stock?threshold=15`);
      if (tab === "expiry")    res = await api.get(`/reports/expiry?days=90`);
      if (tab === "inventory") res = await api.get(`/reports/inventory`);
      setData(res?.data);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, [tab, date, fromDate, toDate]);

  return (
    <div className="page-content">
      {/* Tabs */}
      <div style={{ display: "flex", gap: 4, marginBottom: 20, borderBottom: "1px solid var(--border)", paddingBottom: 0 }}>
        {[
          ["daily",     "Daily Sales"],
          ["range",     "Date Range"],
          ["lowstock",  "Low Stock"],
          ["expiry",    "Expiry Alerts"],
          ["inventory", "Inventory"],
        ].map(([key, label]) => (
          <button
            key={key}
            onClick={() => setTab(key)}
            className="btn btn-ghost btn-sm"
            style={{
              borderRadius: "6px 6px 0 0",
              borderBottom: "2px solid " + (tab === key ? "var(--accent)" : "transparent"),
              color: tab === key ? "var(--accent)" : "var(--text2)",
              background: "transparent", border: "none",
              borderBottom: tab === key ? "2px solid var(--accent)" : "2px solid transparent",
              padding: "8px 16px", fontSize: 13, fontWeight: 600, cursor: "pointer",
            }}
          >
            {label}
          </button>
        ))}
      </div>

      {/* Date controls */}
      {tab === "daily" && (
        <div className="gap-8" style={{ marginBottom: 20, alignItems: "center" }}>
          <span style={{ fontSize: 12, color: "var(--text3)" }}>Date</span>
          <input className="input" style={{ width: 160 }} type="date" value={date} onChange={e=>setDate(e.target.value)} />
        </div>
      )}
      {tab === "range" && (
        <div className="gap-8" style={{ marginBottom: 20, alignItems: "center" }}>
          <span style={{ fontSize: 12, color: "var(--text3)" }}>From</span>
          <input className="input" style={{ width: 160 }} type="date" value={fromDate} onChange={e=>setFromDate(e.target.value)} />
          <span style={{ fontSize: 12, color: "var(--text3)" }}>To</span>
          <input className="input" style={{ width: 160 }} type="date" value={toDate} onChange={e=>setToDate(e.target.value)} />
        </div>
      )}

      {loading && <div className="empty-state"><span className="spinner" /></div>}

      {/* ── Daily ── */}
      {!loading && tab === "daily" && data && (
        <div>
          <div className="stat-grid" style={{ marginBottom: 20 }}>
            {[
              ["Bills",       data.summary?.bills,                     ""],
              ["Revenue",     `₹${parseFloat(data.summary?.total||0).toFixed(2)}`,  ""],
              ["GST",         `₹${parseFloat(data.summary?.gst_amount||0).toFixed(2)}`, ""],
              ["Discounts",   `₹${parseFloat(data.summary?.discount||0).toFixed(2)}`,  ""],
            ].map(([label, value]) => (
              <div className="stat-card" key={label}>
                <div className="label">{label}</div>
                <div className="value mono">{value}</div>
              </div>
            ))}
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
            <div className="card">
              <div className="card-title">Top Products</div>
              {data.topProducts?.length === 0 && <div style={{ color: "var(--text3)", fontSize: 13 }}>No sales today</div>}
              {data.topProducts?.map((p, i) => (
                <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "6px 0", borderBottom: "1px solid rgba(42,58,85,0.4)", fontSize: 13 }}>
                  <span>{p.name}</span>
                  <span className="mono" style={{ color: "var(--accent2)" }}>×{p.qty_sold} &nbsp; ₹{parseFloat(p.revenue).toFixed(2)}</span>
                </div>
              ))}
            </div>
            <div className="card">
              <div className="card-title">By Payment Mode</div>
              {data.byPayment?.map((p, i) => (
                <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "6px 0", borderBottom: "1px solid rgba(42,58,85,0.4)", fontSize: 13 }}>
                  <span>{p.payment_mode}</span>
                  <span className="mono">{p.count} bills — <span style={{ color: "var(--accent2)" }}>₹{parseFloat(p.total).toFixed(2)}</span></span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ── Range ── */}
      {!loading && tab === "range" && data && (
        <div>
          <div className="stat-grid" style={{ marginBottom: 20 }}>
            {[
              ["Bills",    data.totals?.bills],
              ["Revenue",  `₹${parseFloat(data.totals?.revenue||0).toFixed(2)}`],
              ["GST",      `₹${parseFloat(data.totals?.gst||0).toFixed(2)}`],
              ["Discount", `₹${parseFloat(data.totals?.discount||0).toFixed(2)}`],
            ].map(([label, value]) => (
              <div className="stat-card" key={label}>
                <div className="label">{label}</div>
                <div className="value mono">{value}</div>
              </div>
            ))}
          </div>
          <div className="table-wrap">
            <table>
              <thead>
                <tr><th>Date</th><th className="text-right">Bills</th><th className="text-right">Revenue</th><th className="text-right">GST</th></tr>
              </thead>
              <tbody>
                {data.daily?.length === 0 && (
                  <tr><td colSpan={4} className="text-center" style={{ padding: 24, color: "var(--text3)" }}>No data</td></tr>
                )}
                {data.daily?.map((d, i) => (
                  <tr key={i}>
                    <td className="mono" style={{ fontSize: 12 }}>{d.day}</td>
                    <td className="text-right mono">{d.bills}</td>
                    <td className="text-right mono" style={{ color: "var(--accent2)", fontWeight: 700 }}>₹{parseFloat(d.revenue).toFixed(2)}</td>
                    <td className="text-right mono">₹{parseFloat(d.gst).toFixed(2)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* ── Low Stock ── */}
      {!loading && tab === "lowstock" && data && (
        <div>
          <div className="alert alert-warn" style={{ marginBottom: 16 }}>
            ⚠ Showing items with stock ≤ 15 units
          </div>
          <div className="table-wrap">
            <table>
              <thead>
                <tr><th>Product</th><th>Category</th><th>Batch</th><th>Expiry</th><th className="text-right">Stock</th><th className="text-right">MRP</th></tr>
              </thead>
              <tbody>
                {data.length === 0 && (
                  <tr><td colSpan={6} className="text-center" style={{ padding: 24, color: "var(--text3)" }}>✅ All products are adequately stocked</td></tr>
                )}
                {data.map((r, i) => (
                  <tr key={i}>
                    <td style={{ fontWeight: 600 }}>{r.name}</td>
                    <td><span className={`badge badge-${r.category?.toLowerCase()}`}>{r.category}</span></td>
                    <td className="mono" style={{ fontSize: 12, color: "var(--accent)" }}>{r.batch_no}</td>
                    <td className="mono" style={{ fontSize: 12 }}>{r.expiry}</td>
                    <td className="text-right mono" style={{ fontWeight: 700, color: r.quantity <= 5 ? "var(--danger)" : "var(--warn)" }}>{r.quantity}</td>
                    <td className="text-right mono">₹{r.selling_price}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* ── Expiry ── */}
      {!loading && tab === "expiry" && data && (
        <div>
          <div className="alert alert-warn" style={{ marginBottom: 16 }}>
            ⚠ Showing items expiring within 90 days
          </div>
          <div className="table-wrap">
            <table>
              <thead>
                <tr><th>Product</th><th>Batch</th><th>Expiry</th><th className="text-right">Days Left</th><th className="text-right">Stock</th></tr>
              </thead>
              <tbody>
                {data.length === 0 && (
                  <tr><td colSpan={5} className="text-center" style={{ padding: 24, color: "var(--text3)" }}>✅ No items expiring soon</td></tr>
                )}
                {data.map((r, i) => {
                  const d = Math.floor(r.days_left);
                  const color = d < 0 ? "var(--danger)" : d < 30 ? "var(--danger)" : "var(--warn)";
                  return (
                    <tr key={i}>
                      <td style={{ fontWeight: 600 }}>{r.name}</td>
                      <td className="mono" style={{ fontSize: 12, color: "var(--accent)" }}>{r.batch_no}</td>
                      <td className="mono" style={{ fontSize: 12 }}>{r.expiry}</td>
                      <td className="text-right mono" style={{ fontWeight: 700, color }}>
                        {d < 0 ? "EXPIRED" : `${d}d`}
                      </td>
                      <td className="text-right mono">{r.quantity}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* ── Inventory ── */}
      {!loading && tab === "inventory" && data && (
        <div>
          <div className="stat-grid" style={{ marginBottom: 20 }}>
            {[
              ["Products",    data.length],
              ["Total Stock", data.reduce((s,r)=>s+r.total_qty,0)],
              ["Stock Value", `₹${data.reduce((s,r)=>s+r.stock_value,0).toFixed(2)}`],
            ].map(([label, value]) => (
              <div className="stat-card" key={label}>
                <div className="label">{label}</div>
                <div className="value mono">{value}</div>
              </div>
            ))}
          </div>
          <div className="table-wrap">
            <table>
              <thead>
                <tr><th>Product</th><th>Category</th><th>HSN</th><th>GST</th><th className="text-right">Batches</th><th className="text-right">Stock</th><th className="text-right">Value</th></tr>
              </thead>
              <tbody>
                {data.map((r, i) => (
                  <tr key={i}>
                    <td style={{ fontWeight: 600 }}>{r.name}</td>
                    <td><span className={`badge badge-${r.category?.toLowerCase()}`}>{r.category}</span></td>
                    <td className="mono" style={{ fontSize: 11, color: "var(--text3)" }}>{r.hsn || "—"}</td>
                    <td className="mono">{r.gst}%</td>
                    <td className="text-right mono">{r.batch_count}</td>
                    <td className="text-right mono" style={{ fontWeight: 700, color: r.total_qty > 10 ? "var(--success)" : r.total_qty > 0 ? "var(--warn)" : "var(--danger)" }}>{r.total_qty}</td>
                    <td className="text-right mono" style={{ color: "var(--accent2)" }}>₹{parseFloat(r.stock_value).toFixed(2)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}
