// src/utils/receipt.js

export function formatReceipt(sale, settings = {}) {
  const shop    = settings.shop_name    || "MediCare Pharmacy";
  const address = settings.shop_address || "";
  const phone   = settings.shop_phone   || "";
  const gstin   = settings.shop_gstin   || "";
  const W = 42;

  const center = (s) => {
    const pad = Math.max(0, Math.floor((W - s.length) / 2));
    return " ".repeat(pad) + s;
  };
  const line  = (c = "-") => c.repeat(W);
  const cols  = (l, r) => {
    const space = W - l.length - r.length;
    return l + " ".repeat(Math.max(1, space)) + r;
  };
  const fmt   = (n) => "Rs." + parseFloat(n || 0).toFixed(2);

  const date = new Date(sale.date).toLocaleString("en-IN", {
    day: "2-digit", month: "short", year: "numeric",
    hour: "2-digit", minute: "2-digit", hour12: true,
  });

  // Recalculate GST from items (GST inclusive)
  let totalGst  = 0;
  let totalBase = 0;
  for (const item of (sale.items || [])) {
    const lt = item.quantity * item.unit_price;
    const gstRate = parseFloat(item.gst_rate || 0);
    const gst  = lt - lt / (1 + gstRate / 100);
    totalGst  += gst;
    totalBase += lt - gst;
  }

  let r = "";
  r += center(shop)      + "\n";
  if (address) r += center(address) + "\n";
  if (phone)   r += center("Ph: " + phone) + "\n";
  if (gstin)   r += center("GSTIN: " + gstin) + "\n";
  r += line()            + "\n";
  r += "Invoice: " + sale.invoice_no + "\n";
  r += "Date   : " + date + "\n";
  if (sale.customer && sale.customer !== "Walk-in")
    r += "Patient: " + sale.customer + "\n";
  r += "Payment: " + (sale.payment_mode || "Cash") + "\n";
  r += line()            + "\n";
  r += "Item                  Qty   MRP    Amt\n";
  r += line("-")         + "\n";

  for (const item of (sale.items || [])) {
    const name  = (item.product_name || "").substring(0, 18).padEnd(18);
    const qty   = String(item.quantity).padStart(4);
    const rate  = parseFloat(item.unit_price).toFixed(0).padStart(5);
    const amt   = fmt(item.quantity * item.unit_price).padStart(9);
    r += `${name}${qty} ${rate} ${amt}\n`;
    r += `  Batch:${item.batch_no}  Exp:${item.expiry}\n`;
  }

  r += line()            + "\n";
  r += cols("MRP Total:", fmt(sale.total + (parseFloat(sale.discount)||0))) + "\n";
  if (parseFloat(sale.discount) > 0)
    r += cols("Discount:", "-" + fmt(sale.discount)) + "\n";
  r += line("=")         + "\n";
  r += cols("AMOUNT PAID:", fmt(sale.total)) + "\n";
  r += line("=")         + "\n";
  r += "\n";
  r += cols("Taxable Value:", fmt(totalBase)) + "\n";
  r += cols("GST (incl. in MRP):", fmt(totalGst)) + "\n";
  r += line()            + "\n";
  r += center("All prices are MRP inclusive of GST") + "\n";
  r += center("Thank you! Get well soon.") + "\n";
  return r;
}

export function printReceipt(sale, settings) {
  const text = formatReceipt(sale, settings);
  const win  = window.open("", "_blank", "width=420,height=620");
  win.document.write(`
    <html><head><style>
      body { font-family:'Courier New',monospace; font-size:12px;
             white-space:pre; margin:10px; background:#fff; color:#000; }
      @media print { body { margin:0; } }
    </style></head>
    <body>${text}</body></html>
  `);
  win.document.close();
  win.focus();
  setTimeout(() => win.print(), 300);
}