// src/pages/Dashboard.jsx
import { useState, useEffect } from "react";
import api from "../utils/api";

export default function Dashboard() {
  const [daily,    setDaily]    = useState(null);
  const [lowStock, setLowStock] = useState([]);
  const [expiring, setExpiring] = useState([]);
  const [settings, setSettings] = useState({});
  const [loading,  setLoading]  = useState(true);

  useEffect(() => {
    const today = new Date().toISOString().split("T")[0];
    Promise.all([
      api.get(`/reports/daily?date=${today}`),
      api.get(`/reports/low-stock?threshold=10`),
      api.get(`/reports/expiry?days=30`),
      api.get(`/settings`),
    ]).then(([d, ls, exp, s]) => {
      setDaily(d.data);
      setLowStock(ls.data || []);
      setExpiring(exp.data || []);
      setSettings(s.data || {});
    }).finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="empty-state" style={{ paddingTop: 80 }}><span className="spinner" /></div>;

  const shopName = settings.shop_name || "MediCare Pharmacy";

  return (
    <div className="page-content">
      {/* Welcome strip */}
      <div style={{
        background: "linear-gradient(135deg, rgba(0,212,255,0.1) 0%, rgba(0,255,157,0.05) 100%)",
        border: "1px solid rgba(0,212,255,0.2)",
        borderRadius: "var(--radius)", padding: "16px 20px", marginBottom: 20,
        display: "flex", alignItems: "center", justifyContent: "space-between"
      }}>
        <div>
          <div style={{ fontSize: 12, color: "var(--text3)", marginBottom: 2, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase" }}>Welcome back</div>
          <div style={{ fontSize: 20, fontWeight: 800 }}>{shopName}</div>
        </div>
        <div style={{ textAlign: "right", fontFamily: "var(--mono)", fontSize: 12, color: "var(--text2)" }}>
          {new Date().toLocaleDateString("en-IN", { weekday: "long", day: "2-digit", month: "long", year: "numeric" })}
        </div>
      </div>

      {/* Stat cards */}
      <div className="stat-grid" style={{ marginBottom: 20 }}>
        {[
          ["Today's Bills",   daily?.summary?.bills || 0,       ""],
          ["Today's Revenue", `₹${parseFloat(daily?.summary?.total||0).toFixed(2)}`, ""],
          ["GST Collected",   `₹${parseFloat(daily?.summary?.gst_amount||0).toFixed(2)}`, ""],
          ["Low Stock Items", lowStock.length,  lowStock.length > 0 ? "warn" : ""],
          ["Expiring Soon",   expiring.length, expiring.length > 0 ? "danger" : ""],
        ].map(([label, value, color]) => (
          <div className="stat-card" key={label}>
            <div className="label">{label}</div>
            <div className="value mono" style={color ? { color: `var(--${color})` } : {}}>{value}</div>
          </div>
        ))}
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
        {/* Top products today */}
        <div className="card">
          <div className="card-title">Top Products Today</div>
          {!daily?.topProducts?.length ? (
            <div style={{ color: "var(--text3)", fontSize: 13 }}>No sales today yet</div>
          ) : (
            daily.topProducts.slice(0, 7).map((p, i) => (
              <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "7px 0", borderBottom: "1px solid rgba(42,58,85,0.4)", fontSize: 13 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <span style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--text3)", width: 16 }}>{i+1}</span>
                  <span>{p.name}</span>
                </div>
                <div style={{ textAlign: "right" }}>
                  <span style={{ fontFamily: "var(--mono)", color: "var(--accent2)", fontWeight: 700 }}>₹{parseFloat(p.revenue).toFixed(0)}</span>
                  <span style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--text3)", marginLeft: 8 }}>×{p.qty_sold}</span>
                </div>
              </div>
            ))
          )}
        </div>

        {/* Alerts column */}
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Low stock */}
          <div className="card" style={{ flex: 1 }}>
            <div className="card-title" style={{ color: lowStock.length > 0 ? "var(--warn)" : undefined }}>
              {lowStock.length > 0 ? `⚠ Low Stock (${lowStock.length})` : "Low Stock"}
            </div>
            {lowStock.length === 0 ? (
              <div style={{ color: "var(--success)", fontSize: 13 }}>✅ All items adequately stocked</div>
            ) : (
              lowStock.slice(0, 5).map((r, i) => (
                <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "6px 0", borderBottom: "1px solid rgba(42,58,85,0.4)", fontSize: 12 }}>
                  <span style={{ flex: 1 }}>{r.name}</span>
                  <span style={{ fontFamily: "var(--mono)", color: r.quantity <= 5 ? "var(--danger)" : "var(--warn)", fontWeight: 700, marginLeft: 8 }}>
                    {r.quantity} left
                  </span>
                </div>
              ))
            )}
          </div>

          {/* Expiry */}
          <div className="card" style={{ flex: 1 }}>
            <div className="card-title" style={{ color: expiring.length > 0 ? "var(--danger)" : undefined }}>
              {expiring.length > 0 ? `🔴 Expiring in 30d (${expiring.length})` : "Expiry Alerts"}
            </div>
            {expiring.length === 0 ? (
              <div style={{ color: "var(--success)", fontSize: 13 }}>✅ No items expiring in 30 days</div>
            ) : (
              expiring.slice(0, 5).map((r, i) => {
                const d = Math.floor(r.days_left);
                return (
                  <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "6px 0", borderBottom: "1px solid rgba(42,58,85,0.4)", fontSize: 12 }}>
                    <span style={{ flex: 1 }}>{r.name} <span style={{ fontFamily: "var(--mono)", fontSize: 10, color: "var(--text3)" }}>{r.batch_no}</span></span>
                    <span style={{ fontFamily: "var(--mono)", color: d < 0 ? "var(--danger)" : d < 15 ? "var(--danger)" : "var(--warn)", fontWeight: 700, marginLeft: 8 }}>
                      {d < 0 ? "EXPIRED" : `${d}d`}
                    </span>
                  </div>
                );
              })
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
