// src/pages/POS.jsx
import { useState, useEffect, useRef, useCallback } from "react";
import api from "../utils/api";
import { printReceipt } from "../utils/receipt";

export default function POS() {
  const [query,          setQuery]          = useState("");
  const [suggestions,    setSuggestions]    = useState([]);
  const [cart,           setCart]           = useState([]);
  const [customer,       setCustomer]       = useState("");
  const [discount,       setDiscount]       = useState("");
  const [payMode,        setPayMode]        = useState("Cash");
  const [loading,        setLoading]        = useState(false);
  const [error,          setError]          = useState("");
  const [lastSale,       setLastSale]       = useState(null);
  const [showReceipt,    setShowReceipt]    = useState(false);
  const [settings,       setSettings]       = useState({});
  const [lowStockAlerts, setLowStockAlerts] = useState([]);
  const [showAlerts,     setShowAlerts]     = useState(false);
  const [mobilePanel,    setMobilePanel]    = useState("search");

  const searchRef = useRef(null);

  useEffect(() => {
    api.get("/settings").then(r => setSettings(r.data || {}));
    api.get("/reports/low-stock?threshold=10").then(r => {
      const alerts = r.data || [];
      setLowStockAlerts(alerts);
      if (alerts.length > 0) setShowAlerts(true);
    });
    searchRef.current?.focus();
  }, []);

  useEffect(() => {
    if (!query.trim()) { setSuggestions([]); return; }
    const t = setTimeout(async () => {
      try {
        const res = await api.get(`/products?q=${encodeURIComponent(query)}`);
        setSuggestions(res.data || []);
      } catch {}
    }, 220);
    return () => clearTimeout(t);
  }, [query]);

  const addProduct = useCallback(async (product) => {
    if (product.stock === 0) { setError(`${product.name} is out of stock`); return; }
    const existing = cart.find(c => c.product_id === product.id);
    if (existing) {
      setCart(prev => prev.map(c =>
        c.product_id === product.id ? { ...c, qty: c.qty + 1 } : c
      ));
    } else {
      const batchRes = await api.get(`/products/${product.id}/batches`);
      const batches  = batchRes.data || [];
      if (!batches.length) { setError("No stock available"); return; }
      const batch = batches[0]; // FIFO
      setCart(prev => [...prev, {
        product_id:   product.id,
        product_name: product.name,
        category:     product.category,
        gst:          product.gst,
        batch_no:     batch.batch_no,
        expiry:       batch.expiry,
        unit_price:   batch.selling_price, // MRP = GST inclusive
        qty:          1,
        max_qty:      product.stock,
      }]);
    }
    setQuery(""); setSuggestions([]);
    searchRef.current?.focus();
    setError("");
    setMobilePanel("cart"); // switch to cart on mobile after adding
  }, [cart]);

  const updateQty = (product_id, val) => {
    const qty = Math.max(1, parseInt(val) || 1);
    setCart(prev => prev.map(c => c.product_id === product_id ? { ...c, qty } : c));
  };

  const removeItem = (product_id) =>
    setCart(prev => prev.filter(c => c.product_id !== product_id));

  // MRP is GST-inclusive — customer pays MRP only, no extra GST
  const mrpTotal   = cart.reduce((s, c) => s + c.qty * c.unit_price, 0);
  const disc       = parseFloat(discount) || 0;
  const total      = mrpTotal - disc;

  // Extract GST from MRP for informational display on receipt/breakdown
  const gstDisplay  = cart.reduce((s, c) => {
    const lt = c.qty * c.unit_price;
    return s + lt - lt / (1 + (c.gst || 0) / 100);
  }, 0);
  const baseDisplay = mrpTotal - gstDisplay;

  const checkout = async () => {
    if (!cart.length) { setError("Cart is empty"); return; }
    setLoading(true); setError("");
    try {
      const res = await api.post("/sales", {
        items: cart.map(c => ({ product_id: c.product_id, quantity: c.qty })),
        customer: customer || "Walk-in",
        discount: disc,
        payment_mode: payMode,
      });
      setLastSale(res.data);
      setShowReceipt(true);
      setCart([]); setCustomer(""); setDiscount(""); setPayMode("Cash");
      setMobilePanel("search");
      api.get("/reports/low-stock?threshold=10").then(r => {
        setLowStockAlerts(r.data || []);
        if ((r.data || []).length > 0) setShowAlerts(true);
      });
    } catch (e) { setError(e.message); }
    finally { setLoading(false); }
  };

  const handleKeyDown = (e) => {
    if (e.key === "Escape") { setQuery(""); setSuggestions([]); }
    if (e.key === "Enter" && suggestions.length === 1) addProduct(suggestions[0]);
    if (e.key === "F2") checkout();
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100%", overflow: "hidden" }}>

      {/* ── Low Stock Alert Banner ── */}
      {showAlerts && lowStockAlerts.length > 0 && (
        <div style={{
          background: "rgba(245,158,11,0.1)", borderBottom: "1px solid rgba(245,158,11,0.35)",
          padding: "7px 14px", display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap"
        }}>
          <span style={{ fontSize: 13 }}>⚠️</span>
          <span style={{ color: "var(--warn)", fontWeight: 700, fontSize: 11, whiteSpace: "nowrap" }}>LOW STOCK:</span>
          <div style={{ display: "flex", gap: 5, flexWrap: "wrap", flex: 1 }}>
            {lowStockAlerts.slice(0, 5).map((a, i) => (
              <span key={i} style={{
                background: "rgba(245,158,11,0.15)", border: "1px solid rgba(245,158,11,0.3)",
                borderRadius: 4, padding: "1px 7px", fontSize: 11, color: "var(--warn)", fontFamily: "var(--mono)"
              }}>
                {a.name} ({a.quantity})
              </span>
            ))}
            {lowStockAlerts.length > 5 && (
              <span style={{ fontSize: 11, color: "var(--text3)", alignSelf: "center" }}>+{lowStockAlerts.length - 5} more</span>
            )}
          </div>
          <button onClick={() => setShowAlerts(false)}
            style={{ background: "none", border: "none", color: "var(--text3)", cursor: "pointer", fontSize: 15 }}>✕</button>
        </div>
      )}

      {/* ── Mobile tab switcher (hidden on desktop) ── */}
      <div className="mobile-tabs">
        <button
          className={`mobile-tab${mobilePanel === "search" ? " active" : ""}`}
          onClick={() => { setMobilePanel("search"); setTimeout(() => searchRef.current?.focus(), 100); }}
        >🔍 Search</button>
        <button
          className={`mobile-tab${mobilePanel === "cart" ? " active" : ""}`}
          onClick={() => setMobilePanel("cart")}
        >
          🛒 Cart
          {cart.length > 0 && (
            <span style={{
              background: "var(--accent)", color: "#0a0e1a",
              borderRadius: "50%", width: 18, height: 18, fontSize: 10,
              fontWeight: 800, display: "inline-flex", alignItems: "center",
              justifyContent: "center", marginLeft: 6
            }}>{cart.length}</span>
          )}
        </button>
      </div>

      {/* ── Main layout ── */}
      <div className="pos-layout">

        {/* LEFT: Search + Cart */}
        <div className={`pos-left${mobilePanel === "cart" ? " mobile-hidden" : ""}`}>
          {/* Search */}
          <div style={{ padding: "12px 14px", borderBottom: "1px solid var(--border)", background: "var(--bg2)", position: "relative", zIndex: 10 }}>
            <div style={{ position: "relative" }}>
              <span style={{ position: "absolute", left: 10, top: "50%", transform: "translateY(-50%)", color: "var(--text3)" }}>⌕</span>
              <input
                ref={searchRef}
                className="input"
                style={{ paddingLeft: 30, fontSize: 14, fontWeight: 600 }}
                placeholder="Search medicine by name..."
                value={query}
                onChange={e => setQuery(e.target.value)}
                onKeyDown={handleKeyDown}
              />
              {suggestions.length > 0 && (
                <div style={{
                  position: "absolute", top: "100%", left: 0, right: 0, zIndex: 100,
                  background: "var(--bg3)", border: "1px solid var(--border)",
                  borderRadius: "0 0 8px 8px", maxHeight: 280, overflowY: "auto",
                  boxShadow: "0 12px 40px rgba(0,0,0,0.7)"
                }}>
                  {suggestions.map(p => (
                    <div key={p.id} onClick={() => addProduct(p)}
                      style={{ padding: "10px 14px", cursor: "pointer", display: "flex",
                        justifyContent: "space-between", alignItems: "center",
                        borderBottom: "1px solid rgba(42,58,85,0.5)" }}
                      onMouseEnter={e => e.currentTarget.style.background = "var(--bg4)"}
                      onMouseLeave={e => e.currentTarget.style.background = "transparent"}
                    >
                      <div>
                        <div style={{ fontWeight: 600, fontSize: 13 }}>{p.name}</div>
                        <div style={{ fontSize: 11, color: "var(--text3)" }}>
                          GST: {p.gst}% (incl. in MRP) &nbsp;|&nbsp; HSN: {p.hsn || "—"}
                        </div>
                      </div>
                      <div style={{ textAlign: "right", flexShrink: 0, marginLeft: 8 }}>
                        <span className={`badge badge-${p.category?.toLowerCase()}`}>{p.category}</span>
                        <div style={{ fontSize: 11, marginTop: 3, color: p.stock > 10 ? "var(--success)" : p.stock > 0 ? "var(--warn)" : "var(--danger)", fontWeight: 700 }}>
                          {p.stock > 0 ? `${p.stock} in stock` : "Out of stock"}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Cart items */}
          <div style={{ flex: 1, overflowY: "auto" }}>
            {cart.length === 0 ? (
              <div className="empty-state">
                <div className="icon">💊</div>
                <div>Search a medicine to add to cart</div>
                <div style={{ fontSize: 11, marginTop: 6, color: "var(--text3)" }}>Desktop: Press F2 to checkout</div>
              </div>
            ) : (
              <table>
                <thead>
                  <tr>
                    <th>#</th>
                    <th>Medicine</th>
                    <th className="text-right">MRP</th>
                    <th style={{ width: 68 }}>Qty</th>
                    <th className="text-right">Total</th>
                    <th></th>
                  </tr>
                </thead>
                <tbody>
                  {cart.map((item, i) => (
                    <tr key={item.product_id}>
                      <td style={{ color: "var(--text3)", fontFamily: "var(--mono)", fontSize: 11 }}>{i+1}</td>
                      <td>
                        <div style={{ fontWeight: 600, fontSize: 13 }}>{item.product_name}</div>
                        <div style={{ fontSize: 10, color: "var(--text3)" }}>
                          {item.batch_no} · Exp: {item.expiry} · GST {item.gst}% incl.
                        </div>
                      </td>
                      <td className="text-right mono" style={{ fontSize: 13 }}>₹{item.unit_price.toFixed(2)}</td>
                      <td>
                        <input className="input"
                          style={{ padding: "4px 4px", fontSize: 13, textAlign: "center", fontFamily: "var(--mono)" }}
                          type="number" min="1" max={item.max_qty}
                          value={item.qty}
                          onChange={e => updateQty(item.product_id, e.target.value)}
                          onFocus={e => e.target.select()}
                        />
                      </td>
                      <td className="text-right mono" style={{ fontWeight: 700, color: "var(--accent2)", fontSize: 13 }}>
                        ₹{(item.qty * item.unit_price).toFixed(2)}
                      </td>
                      <td>
                        <button className="btn btn-ghost btn-sm" onClick={() => removeItem(item.product_id)}>✕</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>

        {/* RIGHT: Summary */}
        <div className={`pos-right${mobilePanel === "search" ? " mobile-hidden" : ""}`}>
          <div className="card-title" style={{ marginBottom: 12 }}>Bill Summary</div>

          <div className="form-group">
            <label>Customer Name</label>
            <input className="input" placeholder="Walk-in" value={customer} onChange={e => setCustomer(e.target.value)} />
          </div>
          <div className="form-group">
            <label>Payment Mode</label>
            <select className="select" value={payMode} onChange={e => setPayMode(e.target.value)}>
              {["Cash","Card","UPI","Insurance"].map(m => <option key={m}>{m}</option>)}
            </select>
          </div>

          <div style={{ borderTop: "1px solid var(--border)", paddingTop: 12, marginTop: 4 }}>
            {/* GST info box */}
            <div style={{
              background: "var(--bg3)", borderRadius: 6, padding: "8px 10px",
              marginBottom: 10, fontSize: 12, border: "1px solid var(--border)"
            }}>
              <div style={{ fontSize: 10, color: "var(--text3)", fontWeight: 700, letterSpacing: 0.8, textTransform: "uppercase", marginBottom: 6 }}>
                GST Breakdown (Already in MRP)
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 3 }}>
                <span style={{ color: "var(--text2)" }}>Taxable value</span>
                <span className="mono">₹{baseDisplay.toFixed(2)}</span>
              </div>
              <div style={{ display: "flex", justifyContent: "space-between" }}>
                <span style={{ color: "var(--text2)" }}>GST (included)</span>
                <span className="mono">₹{gstDisplay.toFixed(2)}</span>
              </div>
            </div>

            {[
              ["Items", cart.reduce((s,c)=>s+c.qty,0), false],
              ["MRP Total", `₹${mrpTotal.toFixed(2)}`, true],
            ].map(([label, val, mono]) => (
              <div key={label} style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
                <span style={{ color: "var(--text2)", fontSize: 13 }}>{label}</span>
                <span style={{ fontFamily: mono ? "var(--mono)" : "inherit", fontWeight: 600 }}>{val}</span>
              </div>
            ))}

            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 10, alignItems: "center" }}>
              <span style={{ color: "var(--text2)", fontSize: 13 }}>Discount ₹</span>
              <input className="input"
                style={{ width: 90, padding: "4px 8px", fontFamily: "var(--mono)", textAlign: "right" }}
                type="number" min="0" placeholder="0.00"
                value={discount} onChange={e => setDiscount(e.target.value)}
              />
            </div>

            {/* Big total */}
            <div style={{
              background: "var(--bg3)", border: "1px solid var(--accent)",
              borderRadius: "var(--radius)", padding: "12px 14px", marginBottom: 14
            }}>
              <div style={{ fontSize: 11, color: "var(--text3)", marginBottom: 2 }}>PATIENT PAYS (GST incl.)</div>
              <div style={{ fontSize: 28, fontFamily: "var(--mono)", fontWeight: 800, color: "var(--accent)" }}>
                ₹{total.toFixed(2)}
              </div>
              {gstDisplay > 0 && (
                <div style={{ fontSize: 10, color: "var(--text3)", marginTop: 2 }}>
                  Incl. GST ₹{gstDisplay.toFixed(2)}
                </div>
              )}
            </div>

            {error && <div className="alert alert-error" style={{ fontSize: 12, marginBottom: 10 }}>{error}</div>}

            <button
              className="btn btn-success"
              style={{ width: "100%", justifyContent: "center", fontSize: 15, padding: "12px" }}
              onClick={checkout}
              disabled={loading || !cart.length}
            >
              {loading ? <span className="spinner" /> : "✓ Checkout"}
            </button>
            <div style={{ textAlign: "center", fontSize: 10, color: "var(--text3)", marginTop: 8 }}>
              Desktop shortcut: F2
            </div>
          </div>
        </div>
      </div>

      {/* Receipt Modal */}
      {showReceipt && lastSale && (
        <div className="modal-overlay" onClick={() => setShowReceipt(false)}>
          <div className="modal" onClick={e => e.stopPropagation()} style={{ maxWidth: 480, width: "95%" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
              <div>
                <div className="modal-title" style={{ marginBottom: 2 }}>✅ Sale Complete</div>
                <div style={{ fontFamily: "var(--mono)", fontSize: 13, color: "var(--accent)" }}>{lastSale.invoice_no}</div>
              </div>
              <button className="btn btn-ghost btn-sm" onClick={() => setShowReceipt(false)}>✕</button>
            </div>
            <pre style={{
              background: "var(--bg3)", padding: 12, borderRadius: "var(--radius)",
              border: "1px solid var(--border)", fontSize: 11, fontFamily: "var(--mono)",
              lineHeight: 1.6, overflowX: "auto", whiteSpace: "pre-wrap",
              maxHeight: "40vh", overflowY: "auto"
            }}>
              {require("../utils/receipt").formatReceipt(lastSale, settings)}
            </pre>
            <div className="modal-actions">
              <button className="btn btn-ghost" onClick={() => { setShowReceipt(false); setMobilePanel("search"); searchRef.current?.focus(); }}>New Bill</button>
              <button className="btn btn-primary" onClick={() => printReceipt(lastSale, settings)}>🖨 Print</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}