// src/App.jsx
import { useState, useEffect } from "react";
import "./styles/global.css";
import Dashboard from "./pages/Dashboard";
import POS       from "./pages/POS";
import Products  from "./pages/Products";
import Sales     from "./pages/Sales";
import Reports   from "./pages/Reports";
import Settings  from "./pages/Settings";

const NAV = [
  { id: "dashboard", icon: "⬡", label: "Dashboard" },
  { id: "pos",       icon: "⌨", label: "Billing / POS" },
  null,
  { id: "products",  icon: "💊", label: "Products" },
  { id: "sales",     icon: "🧾", label: "Sales History" },
  { id: "reports",   icon: "📊", label: "Reports" },
  null,
  { id: "settings",  icon: "⚙",  label: "Settings" },
];

const PAGE_TITLES = {
  dashboard: { title: "Dashboard",     subtitle: "Overview & alerts" },
  pos:       { title: "Billing / POS", subtitle: "Fast keyboard-first billing" },
  products:  { title: "Products",      subtitle: "Medicines & batches" },
  sales:     { title: "Sales History", subtitle: "Past invoices" },
  reports:   { title: "Reports",       subtitle: "Sales, stock & expiry" },
  settings:  { title: "Settings",      subtitle: "Shop info & preferences" },
};

function Clock() {
  const [time, setTime] = useState(new Date());
  useEffect(() => {
    const t = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(t);
  }, []);
  return (
    <span style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--text3)" }}>
      {time.toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: true })}
    </span>
  );
}

export default function App() {
  const [page,       setPage]       = useState("pos");
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const navigate = (id) => {
    setPage(id);
    setSidebarOpen(false); // close drawer on mobile after nav
  };

  const { title, subtitle } = PAGE_TITLES[page] || {};

  const renderPage = () => {
    switch (page) {
      case "dashboard": return <Dashboard />;
      case "pos":       return <POS />;
      case "products":  return <Products />;
      case "sales":     return <Sales />;
      case "reports":   return <Reports />;
      case "settings":  return <Settings />;
      default:          return <POS />;
    }
  };

  return (
    <div className="app-shell">

      {/* ── Mobile overlay (closes sidebar) ── */}
      <div
        className={`sidebar-overlay${sidebarOpen ? " open" : ""}`}
        onClick={() => setSidebarOpen(false)}
      />

      {/* ── Sidebar ── */}
      <aside className={`sidebar${sidebarOpen ? " open" : ""}`}>
        <div className="sidebar-logo">
          <div className="logo-mark">RX · POS</div>
          <h2>MediCare<br/>Pharmacy</h2>
        </div>

        <nav className="sidebar-nav">
          {NAV.map((item, i) => {
            if (!item) return (
              <div key={`sep-${i}`} style={{ height: 1, background: "var(--border)", margin: "5px 12px" }} />
            );
            return (
              <div
                key={item.id}
                className={`nav-item${page === item.id ? " active" : ""}`}
                onClick={() => navigate(item.id)}
              >
                <span className="nav-icon">{item.icon}</span>
                <span>{item.label}</span>
                {item.id === "pos" && (
                  <span style={{
                    marginLeft: "auto", fontSize: 9, fontFamily: "var(--mono)",
                    background: "var(--accent)", color: "#0a0e1a",
                    padding: "1px 5px", borderRadius: 3, fontWeight: 700
                  }}>F2</span>
                )}
              </div>
            );
          })}
        </nav>

        <div className="sidebar-footer">
          <Clock />
          <div style={{ marginTop: 2, fontSize: 10 }}>Offline · SQLite</div>
        </div>
      </aside>

      {/* ── Main area ── */}
      <div className="main-area">

        {/* Mobile top bar */}
        <div className="mobile-topbar">
          <button className="hamburger" onClick={() => setSidebarOpen(true)}>☰</button>
          <h2>{title}</h2>
          <Clock />
        </div>

        {/* Desktop page header */}
        <div className="page-header">
          <div>
            <h1>{title}</h1>
            <div className="subtitle">{subtitle}</div>
          </div>
        </div>

        {/* Page content */}
        <div style={{ flex: 1, overflow: "hidden", display: "flex", flexDirection: "column" }}>
          {page === "pos" ? (
            <div style={{ flex: 1, overflow: "hidden", display: "flex", flexDirection: "column" }}>
              <POS />
            </div>
          ) : (
            renderPage()
          )}
        </div>
      </div>
    </div>
  );
}