// src/pages/Products.jsx
import { useState, useEffect } from "react";
import api from "../utils/api";

const EMPTY_PRODUCT = { name: "", category: "OTC", gst: 0, hsn: "" };
const EMPTY_BATCH   = { batch_no: "", expiry: "", purchase_price: "", selling_price: "", quantity: "" };

export default function Products() {
  const [products, setProducts] = useState([]);
  const [search,   setSearch]   = useState("");
  const [loading,  setLoading]  = useState(true);
  const [modal,    setModal]    = useState(null); // "add-product" | "edit-product" | "add-batch" | "view-batches"
  const [form,     setForm]     = useState(EMPTY_PRODUCT);
  const [batchForm, setBatchForm] = useState(EMPTY_BATCH);
  const [selected, setSelected] = useState(null); // product for context
  const [batches,  setBatches]  = useState([]);
  const [error,    setError]    = useState("");
  const [saving,   setSaving]   = useState(false);

  const load = async () => {
    setLoading(true);
    try {
      const res = await api.get(`/products?q=${encodeURIComponent(search)}`);
      setProducts(res.data || []);
    } finally { setLoading(false); }
  };

  useEffect(() => { load(); }, [search]);

  const openAdd = () => { setForm(EMPTY_PRODUCT); setError(""); setModal("add-product"); };
  const openEdit = (p) => { setForm({ name: p.name, category: p.category, gst: p.gst, hsn: p.hsn || "" }); setSelected(p); setError(""); setModal("edit-product"); };

  const openBatches = async (p) => {
    setSelected(p);
    const res = await api.get(`/batches?product_id=${p.id}`);
    setBatches(res.data || []);
    setModal("view-batches");
  };

  const openAddBatch = (p) => {
    setSelected(p); setBatchForm(EMPTY_BATCH); setError(""); setModal("add-batch");
  };

  const saveProduct = async () => {
    setSaving(true); setError("");
    try {
      if (modal === "add-product") await api.post("/products", form);
      else await api.put(`/products/${selected.id}`, form);
      setModal(null); load();
    } catch (e) { setError(e.message); }
    finally { setSaving(false); }
  };

  const deleteProduct = async (p) => {
    if (!window.confirm(`Delete "${p.name}"? This will also delete all its batches.`)) return;
    await api.delete(`/products/${p.id}`);
    load();
  };

  const saveBatch = async () => {
    setSaving(true); setError("");
    try {
      await api.post("/batches", { ...batchForm, product_id: selected.id });
      setModal(null); load();
    } catch (e) { setError(e.message); }
    finally { setSaving(false); }
  };

  const deleteBatch = async (b) => {
    if (!window.confirm(`Delete batch ${b.batch_no}?`)) return;
    await api.delete(`/batches/${b.id}`);
    const res = await api.get(`/batches?product_id=${selected.id}`);
    setBatches(res.data || []);
    load();
  };

  return (
    <div className="page-content">
      {/* Header */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
        <input
          className="input" style={{ width: 300 }}
          placeholder="Search products..."
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
        <button className="btn btn-primary" onClick={openAdd}>+ Add Product</button>
      </div>

      {loading ? (
        <div className="empty-state"><span className="spinner" /></div>
      ) : (
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Name</th>
                <th>Category</th>
                <th>HSN</th>
                <th>GST %</th>
                <th className="text-right">Stock</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {products.length === 0 && (
                <tr><td colSpan={6} className="text-center" style={{ padding: "32px", color: "var(--text3)" }}>
                  No products found
                </td></tr>
              )}
              {products.map(p => (
                <tr key={p.id}>
                  <td style={{ fontWeight: 600 }}>{p.name}</td>
                  <td><span className={`badge badge-${p.category?.toLowerCase()}`}>{p.category}</span></td>
                  <td className="mono" style={{ fontSize: 12, color: "var(--text2)" }}>{p.hsn || "—"}</td>
                  <td className="mono">{p.gst}%</td>
                  <td className="text-right mono" style={{ color: p.stock > 10 ? "var(--success)" : p.stock > 0 ? "var(--warn)" : "var(--danger)", fontWeight: 700 }}>
                    {p.stock}
                  </td>
                  <td>
                    <div className="gap-8">
                      <button className="btn btn-ghost btn-sm" onClick={() => openBatches(p)}>Batches</button>
                      <button className="btn btn-ghost btn-sm" onClick={() => openAddBatch(p)}>+ Batch</button>
                      <button className="btn btn-ghost btn-sm" onClick={() => openEdit(p)}>Edit</button>
                      <button className="btn btn-danger btn-sm" onClick={() => deleteProduct(p)}>Del</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* ─── Add/Edit Product Modal ─── */}
      {(modal === "add-product" || modal === "edit-product") && (
        <div className="modal-overlay">
          <div className="modal">
            <div className="modal-title">{modal === "add-product" ? "Add Product" : "Edit Product"}</div>
            {error && <div className="alert alert-error">{error}</div>}
            <div className="form-group">
              <label>Product Name *</label>
              <input className="input" value={form.name} onChange={e=>setForm({...form,name:e.target.value})} placeholder="e.g. Paracetamol 500mg" autoFocus />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label>Category *</label>
                <select className="select" value={form.category} onChange={e=>setForm({...form,category:e.target.value})}>
                  {["PMBI","Branded","OTC"].map(c=><option key={c}>{c}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label>GST %</label>
                <input className="input" type="number" min="0" max="28" value={form.gst} onChange={e=>setForm({...form,gst:e.target.value})} />
              </div>
            </div>
            <div className="form-group">
              <label>HSN Code</label>
              <input className="input" value={form.hsn} onChange={e=>setForm({...form,hsn:e.target.value})} placeholder="e.g. 30049099" />
            </div>
            <div className="modal-actions">
              <button className="btn btn-ghost" onClick={()=>setModal(null)}>Cancel</button>
              <button className="btn btn-primary" onClick={saveProduct} disabled={saving}>
                {saving ? <span className="spinner"/> : "Save"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ─── Add Batch Modal ─── */}
      {modal === "add-batch" && selected && (
        <div className="modal-overlay">
          <div className="modal">
            <div className="modal-title">Add Batch — {selected.name}</div>
            {error && <div className="alert alert-error">{error}</div>}
            <div className="form-row">
              <div className="form-group">
                <label>Batch Number *</label>
                <input className="input" value={batchForm.batch_no} onChange={e=>setBatchForm({...batchForm,batch_no:e.target.value})} placeholder="e.g. BT2024001" autoFocus />
              </div>
              <div className="form-group">
                <label>Expiry Date *</label>
                <input className="input" type="date" value={batchForm.expiry} onChange={e=>setBatchForm({...batchForm,expiry:e.target.value})} />
              </div>
            </div>
            <div className="form-row-3">
              <div className="form-group">
                <label>Purchase Price ₹</label>
                <input className="input" type="number" step="0.01" value={batchForm.purchase_price} onChange={e=>setBatchForm({...batchForm,purchase_price:e.target.value})} placeholder="0.00" />
              </div>
              <div className="form-group">
                <label>Selling Price ₹ *</label>
                <input className="input" type="number" step="0.01" value={batchForm.selling_price} onChange={e=>setBatchForm({...batchForm,selling_price:e.target.value})} placeholder="0.00" />
              </div>
              <div className="form-group">
                <label>Quantity *</label>
                <input className="input" type="number" min="1" value={batchForm.quantity} onChange={e=>setBatchForm({...batchForm,quantity:e.target.value})} placeholder="0" />
              </div>
            </div>
            <div className="modal-actions">
              <button className="btn btn-ghost" onClick={()=>setModal(null)}>Cancel</button>
              <button className="btn btn-primary" onClick={saveBatch} disabled={saving}>
                {saving ? <span className="spinner"/> : "Save Batch"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ─── View Batches Modal ─── */}
      {modal === "view-batches" && selected && (
        <div className="modal-overlay">
          <div className="modal" style={{ maxWidth: 640 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
              <div className="modal-title" style={{ marginBottom: 0 }}>Batches — {selected.name}</div>
              <button className="btn btn-ghost btn-sm" onClick={()=>setModal(null)}>✕</button>
            </div>
            {batches.length === 0 ? (
              <div className="empty-state">No batches found</div>
            ) : (
              <div className="table-wrap">
                <table>
                  <thead>
                    <tr>
                      <th>Batch No</th>
                      <th>Expiry</th>
                      <th>MRP ₹</th>
                      <th>Purchase ₹</th>
                      <th className="text-right">Stock</th>
                      <th></th>
                    </tr>
                  </thead>
                  <tbody>
                    {batches.map(b => {
                      const daysLeft = Math.floor((new Date(b.expiry)-new Date())/(1000*86400));
                      return (
                        <tr key={b.id}>
                          <td className="mono" style={{ color: "var(--accent)" }}>{b.batch_no}</td>
                          <td className="mono" style={{ fontSize: 12, color: daysLeft < 30 ? "var(--danger)" : daysLeft < 90 ? "var(--warn)" : "var(--text)" }}>
                            {b.expiry} {daysLeft < 0 ? "⚠ EXPIRED" : daysLeft < 90 ? `(${daysLeft}d)` : ""}
                          </td>
                          <td className="mono">₹{b.selling_price}</td>
                          <td className="mono">₹{b.purchase_price}</td>
                          <td className="text-right mono" style={{ fontWeight: 700, color: b.quantity > 10 ? "var(--success)" : b.quantity > 0 ? "var(--warn)" : "var(--danger)" }}>
                            {b.quantity}
                          </td>
                          <td>
                            <button className="btn btn-danger btn-sm" onClick={()=>deleteBatch(b)}>Del</button>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
